uv run --no-project --python 3.13 --with pillow --with piexif python -c "
import os, hashlib
from PIL import Image
import piexif

photo_dir = 'uploads/photos'
all_files = []
for root, dirs, files in os.walk(photo_dir):
    for f in files:
        if f.lower().endswith(('.jpg', '.jpeg', '.png')):
            all_files.append(os.path.join(root, f))

print(f'Total image files: {len(all_files)}')

# Extract EXIF data
files_with_exif = 0
exif_data = {}

for fp in sorted(all_files):
    try:
        exif_dict = piexif.load(fp)
        dt = exif_dict.get('Exif', {}).get(piexif.ExifIFD.DateTimeOriginal)
        if dt:
            dt_str = dt.decode('utf-8') if isinstance(dt, bytes) else dt
            exif_data[fp] = dt_str
            files_with_exif += 1
            print(f'  EXIF: {fp} -> {dt_str}')
        else:
            print(f'  No EXIF DateTimeOriginal: {fp}')
    except Exception as e:
        print(f'  Error reading EXIF from {fp}: {e}')

print(f'Files with EXIF: {files_with_exif}')
" 2>&1

