uv run --no-project --python 3.13 --with pillow python -c "
import os, hashlib
from PIL import Image

photo_dir = 'uploads/photos'
all_files = []
for root, dirs, files in os.walk(photo_dir):
    for f in files:
        if f.lower().endswith(('.jpg', '.jpeg', '.png')):
            all_files.append(os.path.join(root, f))

# Compute MD5 of raw pixel data
hash_map = {}
duplicate_pairs = []

for fp in sorted(all_files):
    try:
        img = Image.open(fp)
        img = img.convert('RGB')  # normalize mode
        pixel_bytes = img.tobytes()
        md5 = hashlib.md5(pixel_bytes).hexdigest()
        if md5 in hash_map:
            duplicate_pairs.append((hash_map[md5], fp))
            print(f'  DUPLICATE: {fp} == {hash_map[md5]}  [md5={md5}]')
        else:
            hash_map[md5] = fp
    except Exception as e:
        print(f'  Error hashing {fp}: {e}')

print(f'Total duplicate pairs: {len(duplicate_pairs)}')
" 2>&1

